                                if target_dnos:
                                    console.print(f"  • DNOS: [green]{target_dnos}[/green]")
                                if target_gi:
                                    console.print(f"  • GI:   [green]{target_gi}[/green]")
                                if target_baseos:
                                    console.print(f"  • BaseOS: [green]{target_baseos}[/green]")
                                
                                # Get deploy parameters from user
