        if iface_choice == "e" or iface_choice == "7":
            # Set L3 mode flag if option 7 was selected
            is_l3_mode = (iface_choice == "7")
            if is_l3_mode:
                state._l3_subif_mode = True
                console.print("\n[bold cyan]L3 Sub-interface Configuration[/bold cyan]")
                console.print("[dim]Creates ge/bundle.Y with IP addressing (for L3 routing)[/dim]")
            else:
                state._l3_subif_mode = False
            if not state.current_config:
                console.print("[yellow]No current configuration available to detect existing interfaces[/yellow]")
                continue
            
            # Get existing physical and bundle parent interfaces
            existing_interfaces = _get_all_interfaces_from_config(state.current_config)
            categories = categorize_interfaces_by_type(existing_interfaces)
            
