        existing = manager.get_all_community_list_names()
        if existing:
            console.print(f"  [dim]Existing: {', '.join(existing[:5])}{'...' if len(existing) > 5 else ''}[/dim]")
        
        console.print("  [1] Create community-list")
        console.print("  [2] View existing")
        console.print("  [3] Delete community-list")
        console.print("  [B] Back")
        
        choice = Prompt.ask("Select", choices=["1", "2", "3", "b", "B"], default="1").lower()
        
        if choice == "b":
            return
        
        elif choice == "1":
            name = Prompt.ask("  Community-list name", default="CL_EXAMPLE")
            if name.lower() == 'b':
                continue
            
            builder = CommunityListBuilder(name=name)
            
            console.print("  [dim]Enter community rules (empty to finish):[/dim]")
            console.print("  [dim]Formats: value AS:ID | well-known <name> | regex <pattern>[/dim]")
            
            rule_id = 10
            while True:
                rule_input = Prompt.ask(f"    Rule {rule_id}", default="").strip()
                if not rule_input or rule_input.lower() == 'b':
                    break
                
                parts = rule_input.split()
                if not parts:
                    continue
                
                action = RuleAction.ALLOW
                match_type = "value"
                value = ""
                
                i = 0
                if parts[i] in ('allow', 'deny'):
                    action = RuleAction(parts[i])
                    i += 1
                
                if i < len(parts):
                    if parts[i] == 'value' and i + 1 < len(parts):
                        match_type = "value"
                        value = parts[i + 1]
                    elif parts[i] == 'well-known' and i + 1 < len(parts):
                        match_type = "well-known"
                        value = parts[i + 1]
                    elif parts[i] == 'regex' and i + 1 < len(parts):
                        match_type = "regex"
                        value = ' '.join(parts[i + 1:])
                    else:
                        # Assume value format
                        value = parts[i]
                
                if value:
                    builder.add_rule(rule_id, action, match_type, value)
                    console.print(f"    [green]✓ Added: {match_type} {value}[/green]")
                    rule_id += 10
            
            if builder.rules:
                manager.add_community_list(builder.build())
                console.print(f"[green]✓ Community-list '{name}' created[/green]")
        
        elif choice == "2":
            if not existing:
                console.print("[yellow]No community-lists configured[/yellow]")
            else:
                for name in existing:
                    cl = manager.community_lists.get(name)
                    if cl:
                        console.print(f"  {name}: {len(cl.rules)} rules")
        
        elif choice == "3":
            if not existing:
                console.print("[yellow]No community-lists to delete[/yellow]")
                continue
            
            for i, name in enumerate(existing, 1):
                console.print(f"  [{i}] {name}")
            
            del_choice = Prompt.ask("Number to delete", default="").strip()
            if del_choice.isdigit():
                idx = int(del_choice) - 1
                if 0 <= idx < len(existing):
                    name = existing[idx]
                    if manager.delete_community_list(name):
                        console.print(f"[green]✓ Deleted: {name}[/green]")


